It seems that this PR https://github.com/exceljs/exceljs/pull/2614 fixes the issue, but it hasn't been merged yet. You can use the following patch before the PR gets merged:

[Example](https://stackblitz.com/edit/exceljs-addimage-ekdbmai6?file=src%2FApp.vue)


```typescript
import ExcelJS from 'exceljs'

export function patchExceljsImageAnchor() {
  function getAnchorClass() {
    const wb = new ExcelJS.Workbook()
    const imageId = wb.addImage({
      buffer: new Uint8Array([]),
      extension: 'jpeg',
    })
    const sheet = wb.addWorksheet()
    sheet.addImage(imageId, {
      tl: { col: 0, row: 0 },
      ext: { width: 1, height: 1 },
    })
    const img = sheet.getImages()[0]
    return img.range.tl.constructor
  }

  const anchorClass = getAnchorClass()

  Object.defineProperty(anchorClass.prototype, 'colWidth', {
    get: function () {
      const col = this.worksheet && this.worksheet.getColumn(this.nativeCol + 1)
      const defaultColWidth =
        this.worksheet && this.worksheet.properties && this.worksheet.properties.defaultColWidth
          ? this.worksheet.properties.defaultColWidth
          : 9.02
      const customColWidth = this.worksheet && col && col.width ? col.width : undefined
      const width = customColWidth || defaultColWidth
      return Math.floor(width * 76000)
    },
  })

  Object.defineProperty(anchorClass.prototype, 'rowHeight', {
    get: function () {
      const row = this.worksheet && this.worksheet.getRow(this.nativeRow + 1)
      const defaultRowHeight =
        this.worksheet && this.worksheet.properties && this.worksheet.properties.defaultRowHeight
          ? this.worksheet.properties.defaultRowHeight
          : 15
      const customRowHeight = this.worksheet && row && row.height ? row.height : undefined
      const height = customRowHeight || defaultRowHeight
      return Math.floor(height * 12700)
    },
  })
}

```
